import React from 'react';

function Projects({ data }) {
  if (!data || data.length === 0) return null;

  return (
    <section id="projects" className="py-20 bg-white">
      <div className="max-w-7xl mx-auto px-4">
        <h2 className="text-4xl font-bold text-gray-900 mb-16 text-center">My Projects</h2>
        
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {data.map((project, index) => (
            <div 
              key={project.id} 
              className="group cursor-pointer"
            >
              {/* Project Image Container */}
              <div className="relative overflow-hidden rounded-lg bg-gray-100 h-64 md:h-72 mb-5 shadow-lg hover:shadow-xl transition-shadow duration-300">
                <div className="w-full h-full bg-gradient-to-br from-gray-100 to-gray-200 flex items-center justify-center overflow-hidden">
                  {project.image ? (
                    <img 
                      src={project.image} 
                      alt={project.title}
                      className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                    />
                  ) : (
                    <div className="w-full h-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center">
                      <span className="text-6xl">{project.icon}</span>
                    </div>
                  )}
                </div>
              </div>
              
              {/* Project Info */}
              <div className="px-2">
                <h3 className="text-xl font-bold text-gray-900 mb-2 group-hover:text-blue-600 transition-colors duration-200 line-clamp-2">
                  {project.title}
                </h3>
                <p className="text-gray-500 text-sm font-medium mb-4 line-clamp-1">
                  {project.company}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}

export default Projects;
